// Helper to get unique states
export const STATES = [...new Set(AIRPORTS.map(a => a.state))].sort();

// Helper to find airport by code
export function findAirport(code) {
  const q = code.toUpperCase();
  return AIRPORTS.find(a => a.faa === q || a.iata === q || a.icao === q);
}

// Parse runway string into structured data
export function parseRunways(str) {
  return str.split(";").map(r => {
    const m = r.trim().match(/^(\d+\w?\/\d+\w?):\s*([\d,]+)x(\d+)/);
    if (!m) return null;
    return { id: m[1], length: m[2], width: m[3], lengthNum: parseInt(m[2].replace(/,/g, "")) };
  }).filter(Boolean);
}

// Get airport diagram URL via FlightAware - always current, always correct
export function getDiagramUrl(faaId, icao) {
  if (!icao) return null;
  return "https://www.flightaware.com/resources/airport/" + icao + "/APD/AIRPORT+DIAGRAM";
}
